lexer grammar SYsULexer;

@lexer::members {
    std::string currentFilename = "<unknown>";
    int currentLine = 1;
    int currentCol = 1;
    bool atStartOfLine = true;
    bool hadLeadingSpace = false;

    class PositionedToken : public antlr4::CommonToken {
    public:
        PositionedToken(size_t type, const std::string &text, const std::string &filename, int line, int col, bool startOfLine, bool leadingSpace)
            : CommonToken(type, text), 
              filename(filename), 
              col(col), 
              startOfLine(startOfLine), 
              leadingSpace(leadingSpace) {}

        std::string filename;
        int col;
        bool startOfLine;
        bool leadingSpace;
    };

    void handlePreprocessorDirective(const std::string& text) {
        std::istringstream iss(text.substr(1));
        int lineNum;
        std::string filename;

        if (iss >> lineNum) {
            currentLine = lineNum;

            // Extract filename (may be quoted)
            std::getline(iss, filename);

            // Remove flags part
            size_t spacePos = filename.find(' ');
            if (spacePos != std::string::npos) {
                filename = filename.substr(0, spacePos);
            }

            // Remove quotes if present
            if (filename.size() >= 2 && filename.front() == '"' && filename.back() == '"') {
                filename = filename.substr(1, filename.size() - 2);
            }

            currentFilename = filename;
            currentCol = 1;
            atStartOfLine = true;
            hadLeadingSpace = false;
        }
    }

    virtual antlr4::Token* emit() override {
        auto token = Lexer::emit();

        // Create our custom token
        auto newToken = new PositionedToken(
            token->getType(), 
            token->getText(),
            currentFilename,
            currentLine,
            currentCol,
            atStartOfLine,
            hadLeadingSpace
        );

        // Delete the original token
        delete token;

        // Update position tracking
        currentCol += newToken->getText().size();
        atStartOfLine = false;
        hadLeadingSpace = false;

        return newToken;
    }
}

// Keywords
Int : 'int';
Return : 'return';
If : 'if';
Else : 'else';
While : 'while';
For : 'for';
Break : 'break';
Continue : 'continue';
Const : 'const';

// Operators
Plus : '+';
Minus : '-';
Star : '*';
Div : '/';
Mod : '%';
Equal : '=';
Less : '<';
Greater : '>';
LessEqual : '<=';
GreaterEqual : '>=';
EqualEqual : '==';
NotEqual : '!=';
AndAnd : '&&';
OrOr : '||';
Not : '!';

// Punctuators
LeftParen : '(';
RightParen : ')';
LeftBracket : '[';
RightBracket : ']';
LeftBrace : '{';
RightBrace : '}';
Semi : ';';
Comma : ',';

// Literals
Constant
    :   IntegerConstant
    ;

fragment
IntegerConstant
    :   DecimalConstant
    |   OctalConstant
    |   HexadecimalConstant
    ;

fragment
DecimalConstant
    :   NonzeroDigit Digit*
    ;

fragment
OctalConstant
    :   '0' OctalDigit*
    ;

fragment
HexadecimalConstant
    :   HexadecimalPrefix HexadecimalDigit+
    ;

fragment
HexadecimalPrefix
    :   '0' [xX]
    ;

fragment
NonzeroDigit
    :   [1-9]
    ;

fragment
OctalDigit
    :   [0-7]
    ;

fragment
HexadecimalDigit
    :   [0-9a-fA-F]
    ;

fragment
Digit
    :   [0-9]
    ;

Identifier
    :   IdentifierNondigit
        (   IdentifierNondigit
        |   Digit
        )*
    ;

fragment
IdentifierNondigit
    :   Nondigit
    ;

fragment
Nondigit
    :   [a-zA-Z_]
    ;



// 预处理信息处理，可以从预处理信息中获得文件名以及行号
// 预处理信息中的第一个数字即为行号
LineAfterPreprocessing
    :   '#' Whitespace* ~[\r\n]*
        {
            // Extract line number and filename from preprocessor directive
            std::string text = getText();

            // Use a separate function to avoid scoping issues
            handlePreprocessorDirective(text);
        }
        -> skip
    ;

Whitespace
    :   [ \t]+
        {
            hadLeadingSpace = true;
            currentCol += getText().size();
        }
        -> skip
    ;

// 换行符号，可以利用这个信息来更新行号
Newline
    :   (   '\r' '\n'?
        |   '\n'
        )
        {
            currentLine++;
            currentCol = 1;
            atStartOfLine = true;
            hadLeadingSpace = false;
        }
        -> skip
    ;

